package com.bank.service;

import com.bank.model.BankingTransaction;
import com.bank.model.TransactionRequest;
import com.bank.model.TransactionResponse;

import javax.annotation.Resource;
import javax.jws.WebService;
import javax.xml.ws.WebServiceContext;
import javax.xml.ws.handler.MessageContext;
import java.math.BigDecimal;
import java.util.Date;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

@WebService(
    endpointInterface = "com.bank.service.BankingService",
    targetNamespace = "http://bank.com/ws",
    serviceName = "BankingService",
    portName = "BankingServicePort"
)
public class BankingServiceImpl implements BankingService {

    @Resource
    private WebServiceContext wsContext;

    private static final Map<String, BankingTransaction> transactions = new ConcurrentHashMap<>();
    private static final Map<String, BigDecimal> accountBalances = new ConcurrentHashMap<>();

    static {
        accountBalances.put("ACC001", new BigDecimal("10000.00"));
        accountBalances.put("ACC002", new BigDecimal("5000.00"));
        accountBalances.put("ACC003", new BigDecimal("15000.00"));
    }

    @Override
    public TransactionResponse processTransaction(TransactionRequest request) {
        try {
            validateRequest(request);

            String transactionId = UUID.randomUUID().toString();
            
            BigDecimal fromBalance = accountBalances.get(request.getFromAccount());
            BigDecimal toBalance = accountBalances.get(request.getToAccount());

            if (fromBalance == null) {
                return new TransactionResponse(false, null, 
                    "Source account not found", null);
            }

            if (toBalance == null) {
                return new TransactionResponse(false, null, 
                    "Destination account not found", null);
            }

            if (fromBalance.compareTo(request.getAmount()) < 0) {
                return new TransactionResponse(false, null, 
                    "Insufficient funds", null);
            }

            accountBalances.put(request.getFromAccount(), 
                fromBalance.subtract(request.getAmount()));
            accountBalances.put(request.getToAccount(), 
                toBalance.add(request.getAmount()));

            BankingTransaction transaction = new BankingTransaction(
                transactionId,
                request.getFromAccount(),
                request.getToAccount(),
                request.getAmount(),
                request.getCurrency(),
                new Date(),
                "COMPLETED",
                request.getDescription()
            );

            transactions.put(transactionId, transaction);

            return new TransactionResponse(true, transactionId, 
                "Transaction processed successfully", transaction);

        } catch (Exception e) {
            return new TransactionResponse(false, null, 
                "Transaction failed: " + e.getMessage(), null);
        }
    }

    @Override
    public BankingTransaction getTransactionStatus(String transactionId) {
        return transactions.get(transactionId);
    }

    @Override
    public String getAccountBalance(String accountNumber) {
        BigDecimal balance = accountBalances.get(accountNumber);
        if (balance != null) {
            return balance.toString();
        }
        return "Account not found";
    }

    private void validateRequest(TransactionRequest request) throws Exception {
        if (request.getFromAccount() == null || request.getFromAccount().isEmpty()) {
            throw new Exception("Source account is required");
        }
        if (request.getToAccount() == null || request.getToAccount().isEmpty()) {
            throw new Exception("Destination account is required");
        }
        if (request.getAmount() == null || request.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            throw new Exception("Invalid amount");
        }
        if (request.getCurrency() == null || request.getCurrency().isEmpty()) {
            throw new Exception("Currency is required");
        }
    }
}

